/**
 * x402-stellar — Freighter wallet client
 *
 * A fetch-compatible wrapper that automatically handles x402 payment challenges
 * using the Freighter browser extension. Designed for browser dApps.
 */
import { TransactionBuilder } from "@stellar/stellar-sdk";
import { CAIP2_NETWORKS, HEADERS, X402_VERSION } from "../constants.js";
import type {
  FreighterClientConfig,
  StellarNetworkAlias,
  StellarPaymentPayload,
  StellarPaymentRequired,
  StellarPaymentRequirements,
} from "../types.js";
import { encodeHeader, safeDecodeHeader } from "../utils.js";
import { buildPaymentTransaction } from "./transaction.js";

// ── x402FreighterFetch ────────────────────────────────────────────────────────

/**
 * Create a fetch-compatible function that automatically pays x402 challenges
 * on Stellar using the Freighter browser extension.
 *
 * Call this in browser environments (Next.js client components, React apps).
 * Requires `@stellar/freighter-api` to be installed.
 *
 * @example
 * ```ts
 * import { x402FreighterFetch } from 'x402-stellar';
 *
 * const fetch = x402FreighterFetch({ network: 'testnet' });
 *
 * const res = await fetch('https://api.example.com/premium');
 * const data = await res.json();
 * ```
 */
export function x402FreighterFetch(config: FreighterClientConfig): typeof fetch {
  const { network, horizonUrl } = config;

  return async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
    const request = new Request(input, init);

    // ── First attempt (no payment) ─────────────────────────────────────────
    const firstResponse = await globalThis.fetch(request.clone());

    if (firstResponse.status !== 402) {
      return firstResponse;
    }

    // ── Parse 402 response ─────────────────────────────────────────────────
    const paymentRequiredHeader = firstResponse.headers.get(HEADERS.PAYMENT_REQUIRED);
    if (!paymentRequiredHeader) {
      return firstResponse;
    }

    const paymentRequired = safeDecodeHeader<StellarPaymentRequired>(paymentRequiredHeader);
    if (!paymentRequired?.accepts?.length) {
      return firstResponse;
    }

    // ── Find a Stellar requirement we can satisfy ──────────────────────────
    const requirements = findStellarRequirement(paymentRequired.accepts);
    if (!requirements) {
      throw new Error(
        "x402: No compatible Stellar payment requirement found in 402 response",
      );
    }

    // ── Get public key from Freighter ──────────────────────────────────────
    const freighter = await loadFreighter();
    const isConnected = await freighter.isConnected();
    if (!isConnected) {
      throw new Error("x402: Freighter wallet is not connected");
    }

    const { address: publicKey } = await freighter.getAddress();
    if (!publicKey) {
      throw new Error("x402: Could not get public key from Freighter");
    }

    // ── Build and sign the payment transaction ─────────────────────────────
    const networkPassphrase = await getNetworkPassphrase(freighter, network);

    const txXdr = await buildPaymentTransaction(
      {
        sourcePublicKey: publicKey,
        payTo: requirements.payTo,
        asset: resolveAsset(requirements.asset),
        amountBaseUnits: requirements.maxAmountRequired,
        network,
        horizonUrl,
        maxTimeoutSeconds: requirements.maxTimeoutSeconds,
      },
      async (unsignedXdr, passphrase) => {
        const result = await freighter.signTransaction(unsignedXdr, {
          networkPassphrase: passphrase,
        });
        if (result.error) {
          throw new Error(`Freighter signing error: ${result.error}`);
        }
        return result.signedTxXdr;
      },
    );

    // ── Build X-PAYMENT payload ────────────────────────────────────────────
    const paymentPayload: StellarPaymentPayload = {
      x402Version: X402_VERSION,
      scheme: "exact",
      network: requirements.network,
      payload: { transaction: txXdr },
    };

    // ── Retry request with X-PAYMENT header ───────────────────────────────
    const retryHeaders = new Headers(init?.headers);
    retryHeaders.set(HEADERS.X_PAYMENT, encodeHeader(paymentPayload));

    return globalThis.fetch(input, { ...init, headers: retryHeaders });
  };
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function findStellarRequirement(
  accepts: StellarPaymentRequirements[],
): StellarPaymentRequirements | undefined {
  return accepts.find(
    (r) => r.scheme === "exact" && r.network.startsWith("stellar:"),
  );
}

function resolveAsset(onChainAsset: string): "XLM" | "USDC" {
  return onChainAsset === "native" ? "XLM" : "USDC";
}

/** Dynamically import @stellar/freighter-api to keep it truly optional. */
async function loadFreighter(): Promise<FreighterAPI> {
  try {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const mod = await import("@stellar/freighter-api" as any);
    return mod as FreighterAPI;
  } catch {
    throw new Error(
      "x402: @stellar/freighter-api is not installed. " +
        "Run `npm install @stellar/freighter-api` to use Freighter.",
    );
  }
}

async function getNetworkPassphrase(
  freighter: FreighterAPI,
  fallback: StellarNetworkAlias,
): Promise<string> {
  try {
    const { networkPassphrase } = await freighter.getNetworkDetails();
    return networkPassphrase;
  } catch {
    const { NETWORK_PASSPHRASES } = await import("../constants.js");
    return NETWORK_PASSPHRASES[fallback];
  }
}

// ── Minimal Freighter API types (avoids hard dependency on @types) ────────────

interface FreighterAPI {
  isConnected(): Promise<boolean>;
  getAddress(): Promise<{ address: string; error?: string }>;
  signTransaction(
    xdr: string,
    options: { networkPassphrase?: string; network?: string },
  ): Promise<{ signedTxXdr: string; error?: string }>;
  getNetworkDetails(): Promise<{
    network: string;
    networkPassphrase: string;
    networkUrl: string;
  }>;
}
